,p_bind_event_type=>'click'
);
wwv_flow_imp_page.create_page_da_action(
 p_id=>wwv_flow_imp.id(33949300274800007)
,p_event_id=>wwv_flow_imp.id(33949285499800006)
,p_event_result=>'TRUE'
,p_action_sequence=>10
,p_execute_on_page_init=>'N'
,p_action=>'PLUGIN_COM.PLUGIN.MAXPRINT_V2'
,p_attribute_01=>'C'
,p_attribute_02=>'SQL'
,p_attribute_03=>'J'
,p_attribute_05=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'JSON_OBJECT(',
'  ''columns'' VALUE (',
'    SELECT JSON_ARRAYAGG(JOB_TITLE ORDER BY JOB_TITLE)',
'    FROM (',
'      SELECT DISTINCT j.JOB_TITLE',
'      FROM employees e, jobs j',
'      WHERE e.job_id = j.Job_id',
'      ORDER BY j.JOB_TITLE',
'      FETCH FIRST 5 ROWS ONLY',
'    )',
'  ),',
'  ''data'' VALUE (',
'    SELECT JSON_ARRAYAGG(',
'      JSON_OBJECT(',
'        ''Department'' VALUE d.DEPARTMENT_NAME,',
'        ''rows'' VALUE (',
'          SELECT JSON_ARRAYAGG(',
'            COALESCE(emp_count, 0) ORDER BY j.JOB_TITLE',
'          )',
'          FROM (',
'            SELECT DISTINCT j.JOB_TITLE',
'            FROM jobs j',
'            ORDER BY j.JOB_TITLE',
'            FETCH FIRST 5 ROWS ONLY',
'',
'          ) j',
'          LEFT JOIN (',
'            SELECT e.job_id, COUNT(*) as emp_count',
'            FROM employees e',
'            WHERE e.DEPARTMENT_ID = d.DEPARTMENT_ID',
'            GROUP BY e.job_id',
'          ) e ON j.JOB_TITLE = (SELECT JOB_TITLE FROM jobs WHERE job_id = e.job_id FETCH FIRST 5 ROWS ONLY)',
'        )',
'      ) ORDER BY d.DEPARTMENT_NAME',
'    )',
'    FROM DEPARTMENTS d',
'  )',
') AS json_output',
'FROM DUAL;'))
,p_wait_for_result=>'Y'
);
